window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q04"]=window.__LIBQ["the-gioi-hoan-my"]["q04"]||{};window.__LIBQ["the-gioi-hoan-my"]["q04"]["artifacts"]={"updatedAt":"2026-07-21","count":119,"artifacts":[{"id":"tran-ky-phong-toa-san-nho","name":"Trận kỳ phong tỏa sân nhỏ","cn":"","category":"phap-bao","categoryLabel":"Trận kỳ","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã được thu lại","blurb":"Nhiều trận kỳ phát sáng, trói buộc thiên địa và duy trì màn sáng cách ly sân nhỏ trong khách sạn Hổ Môn.","detail":"Các trận kỳ được bố trí quanh sân nhỏ để duy trì đại trận phong tỏa, ngăn cách khu vực bên trong với bên ngoài. Khi viện binh bắt đầu ra tay, chúng bị lấy đi khiến trận pháp tự động mở ra.","nguon":["@c0301"]},{"id":"co-lon-cua-thach-hao","name":"Cờ lớn của Thạch Hạo","cn":"","category":"phap-bao","categoryLabel":"Cờ chiến","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Cây cờ lớn được Thạch Hạo vung lên để làm thiên địa biến ảo và giông tố nổi dậy.","detail":"Trong lần đối mặt đầu tiên với Thạch Tử Minh, Thạch Hạo khẽ vung cây cờ lớn, tạo ra biến động dữ dội của thiên địa và từng cơn giông tố, khiến đối phương ho ra máu.","nguon":["@c0301"]},{"id":"phap-chi-than-linh","name":"Pháp chỉ Thần Linh","cn":"","category":"phap-bao","categoryLabel":"Pháp chỉ","phamCap":"Thần Linh","soHuu":["Vũ tộc"],"trangThai":"Được nhắc lại trong chuyện cũ","blurb":"Pháp chỉ từng được Vũ tộc vận dụng trong cuộc truy sát gia đình Thạch Hạo.","detail":"Vũ tộc từng sử dụng pháp chỉ này với ý định giết sạch gia đình Thạch Hạo và nhổ cỏ tận gốc. Sức mạnh của nó khiến Thạch Tử Lăng bị trọng thương, thân thể trở nên vô cùng suy yếu.","nguon":["@c0301"]},{"id":"bat-hung-kiem","name":"Bát Hung kiếm","cn":"","category":"phap-bao","categoryLabel":"Bộ bảo cụ","phamCap":"Bảo cụ làm từ phù cốt di chủng","soHuu":["Thạch Hạo"],"trangThai":"Đã bị Thạch Hạo đoạt và tế luyện","blurb":"Bộ tám phi kiếm nhiều màu từng được bố trí tại tiền viện Vũ Vương phủ. Thạch Hạo dùng mười Động Thiên cưỡng ép thu lấy toàn bộ rồi tế luyện thành chiến lợi phẩm.","detail":"Tám phi kiếm hiện tại được mài dũa từ phù cốt của tám loại di chủng, là bản thay thế cho bộ kiếm Thượng Cổ vốn cần phù cốt nguyên thủy của chim thần và hung thú thuần huyết trưởng thành. Khi phối hợp cùng kiếm quyết và thần chú trên hộp đá, chúng có thể tạo thành Bát Hung kiếm trận.","phanLoaiPhu":"Bộ tám phi kiếm","hinhDang":"Tám thanh phi kiếm nhiều màu","vatLieu":"Phù cốt của tám loại di chủng","nguonGoc":"Bảo cụ trấn giữ tiền viện Vũ Vương phủ","uyLuc":"Tám kiếm có thể nối tiếp và chồng chất sức mạnh khi vận hành thành kiếm trận.","dacDiem":"Là bản thay thế sử dụng phù cốt di chủng thay cho vật liệu Thái Cổ của bộ kiếm nguyên thủy.","chuHienThoi":"Thạch Hạo","congNang":["Phối hợp tám phi kiếm thành thế công liên hoàn có sức mạnh chồng lớp.","Có thể kết hợp kiếm quyết và thần chú trên hộp đá để tạo Bát Hung kiếm trận."],"chuSoHuu":[{"ten":"Thạch Hạo","tuChuong":"@c0302","denChuong":"","cachCoDuoc":"Dùng mười Động Thiên cưỡng ép thu lấy từ các cao thủ Vũ tộc.","trangThai":"Đang sở hữu"}],"capNhatToi":"@c0302","tabs":{"tienTrinh":[{"chuong":"@c0302","loai":"đổi chủ","importance":"major","giaiDoan":"Rơi vào tay Thạch Hạo","phamCap":"Bảo cụ làm từ phù cốt di chủng","text":"Bát Hung kiếm bị Thạch Hạo dùng mười Động Thiên cưỡng ép đoạt khỏi những cao thủ Vũ tộc rồi tế luyện.","anchor":"nó dùng thủ đoạn cưỡng bức nhưng lại hữu hiệu đoạt lấy những bảo cụ này"}]},"nguon":["@c0302"]},{"id":"hop-da-bat-hung-kiem","name":"Hộp đá Bát Hung kiếm","cn":"","category":"khac","categoryLabel":"Vật phẩm trận đồ","phamCap":"Cổ vật","soHuu":["Thạch Hạo"],"trangThai":"Đang được Thạch Hạo sở hữu","blurb":"Hộp đá dùng chứa tám thanh Bát Hung kiếm, trên mặt khắc thần chú. Thạch Hạo nhận ra cổ vật này có tác dụng tương đương một trận đồ.","detail":"Hộp đá vừa dùng để cất giữ bộ phi kiếm vừa mang thần chú cần thiết cho việc tổ thành Bát Hung kiếm trận. Phát hiện này khiến Thạch Hạo nảy ý định tìm đủ tám khối phù cốt Thái Cổ để tái luyện bộ kiếm chân chính.","phanLoaiPhu":"Hộp chứa kiếm kiêm trận đồ","hinhDang":"Hộp bằng đá có khắc thần chú","nguonGoc":"Đi kèm bộ Bát Hung kiếm của Vũ tộc","dacDiem":"Thần chú trên hộp có tác dụng tương đương trận đồ.","chuHienThoi":"Thạch Hạo","congNang":["Chứa tám thanh Bát Hung kiếm.","Dùng thần chú khắc trên hộp làm trận đồ để tổ thành Bát Hung kiếm trận."],"chuSoHuu":[{"ten":"Thạch Hạo","tuChuong":"@c0302","denChuong":"","cachCoDuoc":"Thu được cùng bộ Bát Hung kiếm tại Vũ Vương phủ.","trangThai":"Đang sở hữu"}],"capNhatToi":"@c0302","tabs":{"tienTrinh":[{"chuong":"@c0302","loai":"khai phong","importance":"major","giaiDoan":"Phát hiện công dụng trận đồ","phamCap":"Cổ vật","text":"Thạch Hạo phát hiện thần chú trên hộp đá có thể đóng vai trò trận đồ để tạo thành Bát Hung kiếm trận chân chính.","anchor":"Thạch Hạo kinh ngạc phát hiện, trên hộp đá có thần chú, việc này làm nó vui mừng, đây là cổ vật, tương đương với trận đồ, có thể tạo thành kiếm trận Bát Hung chân chính."}]},"nguon":["@c0302"]},{"id":"tui-cuong-phong","name":"Túi cuồng phong","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"Uy lực suy giảm sau khi mất người điều khiển","blurb":"Pháp khí dạng túi có thể tạo cuồng phong, cuốn theo cát đá và lưỡi dao ánh sáng do phù văn biến thành.","detail":"Túi cuồng phong được một chiến tướng Vũ tộc sử dụng để vây công Thạch Hạo. Khi người điều khiển bị lôi điện đánh trúng, sức gió do pháp khí tạo ra cũng giảm bớt.","nguon":["@c0303"]},{"id":"trong-than","name":"Trống thần","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"Không rõ","blurb":"Một pháp khí dạng trống, mỗi khi vang lên có thể bắn ra từng luồng tia chớp.","detail":"Trống thần được một chiến tướng Vũ tộc dùng phối hợp với mưa gió và phù văn để vây công Thạch Hạo. Người đánh trống bị lôi điện phản kích đến nổ tung, nhưng kết cục của chiếc trống không được nói rõ.","nguon":["@c0303"]},{"id":"luoi-khon-tien","name":"Lưới Khốn Tiên","cn":"","category":"phap-bao","categoryLabel":"Pháp khí trói bắt","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã bị phá hủy","blurb":"Pháp khí có thể tự truy đuổi, bám sát, trói giữ và luyện hóa mục tiêu bằng phù văn.","detail":"Lưới Khốn Tiên liên tục đuổi theo Thạch Hạo, ghim phù văn lên thân thể để tiến hành luyện hóa. Thạch Hạo bộc phát sức mạnh giữa vòng vây và kéo đứt toàn bộ tấm lưới.","nguon":["@c0303"]},{"id":"to-kiem-tran-tam-thanh-phi-kiem","name":"Tổ kiếm trận tám thanh phi kiếm","cn":"","category":"phap-bao","categoryLabel":"Bộ phi kiếm","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Bộ tám thanh phi kiếm có thể phối hợp thành kiếm trận, khiến uy lực của các kiếm chồng lên nhau.","detail":"Đây là chiến lợi phẩm Thạch Hạo vừa đoạt được rồi dùng trước Vũ Vương phủ. Kiếm trận chém xuyên đội kỵ binh, hung thú và nhiều cường giả Vũ tộc, gây thương vong hàng loạt.","nguon":["@c0303"]},{"id":"tran-ky-vu-vuong-phu","name":"Trận kỳ Vũ Vương phủ","cn":"","category":"phap-bao","categoryLabel":"Bộ pháp khí trận pháp","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"Hơn mười đại kỳ đã bị bẻ gãy","blurb":"Bộ đại kỳ dùng để dựng đại trận phòng thủ Vũ Vương phủ, có thể phóng lớn và dẫn phát sương mù cùng sấm chớp.","detail":"Các đại kỳ được người Vũ tộc triển khai khi Thạch Hạo tiến sâu vào phủ. Trong trạng thái dung hợp Bất Diệt Kim Thân, Thạch Hạo dùng một chưởng phá phù văn và bẻ gãy hơn mười lá cờ, khiến đại trận tan vỡ.","nguon":["@c0303"]},{"id":"bao-thap-cua-vu-toc","name":"Bảo tháp của Vũ tộc","cn":"","category":"phap-bao","categoryLabel":"Pháp khí thu giữ và luyện hóa","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"Đã bị phá hủy hoàn toàn","blurb":"Tòa bảo tháp có khả năng thu giữ mục tiêu vào bên trong và phát thần hà như lửa để luyện hóa.","detail":"Các ông lão giữ phủ dùng bảo tháp thu Thạch Hạo vào trong rồi thúc giục luyện hóa. Thạch Hạo phá tháp từ nội bộ, khiến nó nổ tung; những mảnh vỡ bắn ra xuyên trúng và làm bị thương nặng nhiều tu sĩ Vũ tộc.","nguon":["@c0303"]},{"id":"kinh-thau-cot","name":"Kính Thấu Cốt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thánh vật Thượng Cổ","soHuu":[],"trangThai":"Được Vũ tộc sử dụng","blurb":"Cổ bảo dò xét làm từ nguyên thủy phù cốt, có khả năng soi thấu căn nguyên của sinh linh.","detail":"Kính Thấu Cốt được cất trong hộp đá có lót da thú. Khi thức tỉnh, bảo kính có thể chiếu thần hồn, làm lộ huyết thống và xương cốt bản nguyên; Vũ tộc dùng nó để xác minh lai lịch của Thạch Hạo. Cổ bảo không có sức chiến đấu trực tiếp.","nguon":["@c0306"]},{"id":"bon-cot-dang","name":"Bốn cốt đăng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí trận","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"Một chiếc bị chém hỏng, sau đó cả bốn bị nghiền thành bột","blurb":"Bốn chiếc đèn bằng xương thuộc cổ trận Vũ tộc, có khả năng buông lửa xanh biếc để thiêu đốt và vây nhốt mục tiêu.","detail":"Bốn cốt đăng bay lên từ phế tích, tỏa ánh sáng u tối và bố trí quanh bốn phía để luyện hóa Thạch Hạo ở trung tâm. Một chiếc bị Bát Hung kiếm chém hỏng; sau khi cổ trận tan vỡ, chúng bị chén Hóa Thiên thu lấy và nghiền thành bột.","nguon":["@c0307"]},{"id":"ba-muoi-sau-chien-mau","name":"Ba mươi sáu chiến mâu","cn":"","category":"phap-bao","categoryLabel":"Pháp khí trận","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"Đã bị chặt gãy và nghiền nát","blurb":"Ba mươi sáu chiến mâu là bộ pháp khí công kích nằm trong cổ trận Vũ tộc.","detail":"Các chiến mâu bay ra từ lòng đất trong phế tích, xung kích qua lại như những chùm sáng chói mắt. Chúng bị tám thanh Bát Hung kiếm chặt gãy, sau đó bị chén Hóa Thiên thu lấy và nghiền nát.","nguon":["@c0307"]},{"id":"tam-bien-dong-thau","name":"Tấm biển đồng thau","cn":"","category":"phap-bao","categoryLabel":"Pháp khí trận","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"Đã được kích hoạt trong cổ trận Vũ tộc","blurb":"Tấm biển vốn treo trên cửa chính Vũ tộc nhưng thực chất là trận đồ của một cổ trận.","detail":"Sau khi chú ngữ được đọc, tấm biển đồng thau bay lên, tỏa ánh sáng vàng và đứng yên trong hư không. Nó phối hợp với bốn cốt đăng cùng ba mươi sáu chiến mâu để hình thành cổ trận trói buộc và công kích Thạch Hạo.","nguon":["@c0307"]},{"id":"chen-hoa-thien","name":"Chén Hóa Thiên","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được Thạch Hạo sử dụng","blurb":"Chiếc chén có thể hút tinh khí, thu lấy và nung nấu nhiều loại pháp khí.","detail":"Thạch Hạo dùng chén Hóa Thiên hút tinh khí bốn phía, thu lấy các chiến mâu và cốt đăng của cổ trận Vũ tộc rồi nghiền chúng thành bột. Đáy chén được đúc từ vật liệu có thần tính, nhờ vậy có thể nung nấu nhiều pháp khí.","nguon":["@c0307"]},{"id":"chien-y-mau-den","name":"Chiến y màu đen","cn":"","category":"phap-bao","categoryLabel":"Chiến y","phamCap":"Không nêu rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Chiến y màu đen có thể tiếp nhận các mảnh pháp chỉ Thần Linh đã bị tước sát khí và kim quang.","detail":"Các mảnh pháp chỉ hóa thành từng sợi ánh sáng rồi dung nhập vào chiến y. Trong cuộc đối đầu tại Vũ Vương phủ, chiến y liên tiếp hấp thu những phần pháp chỉ do tiểu tháp phân chia.","nguon":["@c0308"]},{"id":"tui-can-khon-cua-thach-hao","name":"Túi càn khôn của Thạch Hạo","cn":"","category":"khac","categoryLabel":"Vật phẩm chứa đồ","phamCap":"Không nêu rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Túi càn khôn được Thạch Hạo dùng để cất giữ một mảnh pháp chỉ Thần Linh.","detail":"Thạch Hạo giữ mảnh pháp chỉ giàu thần năng trong túi càn khôn, dự định sử dụng khi tiến vào Minh Văn cảnh.","nguon":["@c0308"]},{"id":"dung-cu-bao-ve-tay-cua-thach-tu-dang","name":"Dụng cụ bảo vệ tay của Thạch Tử Đằng","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ hộ thân","phamCap":"Bảo cụ","soHuu":["Thạch Tử Đằng"],"trangThai":"Đang sử dụng","blurb":"Bảo cụ đeo tay giúp Thạch Tử Đằng nhanh chóng tăng mạnh lực chưởng khi giao phong cận chiến.","detail":"Dụng cụ bảo vệ tay phát ra thần lực mênh mông và gia tăng uy lực cho chưởng của Thạch Tử Đằng trong lần đối quyền với Thạch Hạo, nhưng vẫn không thể làm thân thể đối phương bị tổn thương.","nguon":["@c0312"]},{"id":"chien-y-kim-loai-do-tham","name":"Chiến y kim loại đỏ thắm","cn":"","category":"phap-bao","categoryLabel":"Chiến y","phamCap":"","soHuu":["Thạch Tử Đằng"],"trangThai":"Đang sử dụng","blurb":"Chiến y đỏ thắm có thể tự tổ hợp quanh người Thạch Tử Đằng, bảo vệ toàn thân và tạo thành hình thái nhện lớn hình người.","detail":"Bộ chiến y bằng kim loại được chia thành mấy chục mảnh, sau khi lấy ra liền tự động bao kín cơ thể Thạch Tử Đằng. Hai bên chiến y có các chân nhện, khiến người mặc mang hình dáng một con nhện lớn hình người.","nguon":["@c0312"]},{"id":"phuong-thien-hoa-kich-do-tham","name":"Phương Thiên Họa kích đỏ thắm","cn":"","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"Bảo cụ","soHuu":["Thạch Tử Đằng"],"trangThai":"Đang được Thạch Tử Đằng sử dụng","blurb":"Đại kích đỏ thắm có lưỡi cực sắc, phù văn mạnh và sát khí ngập trời, được Thạch Hạo xem là binh khí hạng nặng đáng để tranh đoạt.","detail":"Phương Thiên Họa kích đỏ thắm là binh khí của Thạch Tử Đằng. Nó dễ dàng chém đôi chủy thủ của Thạch Hạo, sau đó dùng phù văn chấn cho bảo cụ ấy nổ tung. Thạch Hạo công khai muốn lấy đại kích làm binh khí hạng nặng của mình.","nguon":["@c0312"]},{"id":"chuy-thu-thanh-lam-vien","name":"Chủy thủ Thanh Lâm viên","cn":"","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"Bảo cụ","soHuu":["Thạch Hạo"],"trangThai":"Đã bị phá hủy","blurb":"Chủy thủ sắc bén được Thạch Hạo mua tại Thanh Lâm viên, dùng để thử uy lực của Phương Thiên Họa kích đỏ thắm.","detail":"Đây không phải vật phàm và có độ sắc bén cao, nhưng khi đối đầu với Phương Thiên Họa kích đỏ thắm, chủy thủ bị chém làm đôi rồi nổ tung dưới chấn động phù văn.","nguon":["@c0312"]},{"id":"chien-kich-huyet-long","name":"Chiến kích Huyết Long","cn":"","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Bị Thạch Hạo đoạt được","blurb":"Chiến kích vốn thuộc về Thạch Tử Đằng, sau đó rơi vào tay Thạch Hạo khi hắn đại bại.","detail":"Việc Thạch Tử Đằng để mất Chiến kích Huyết Long sau thất bại trước Thạch Hạo bị dư luận Hoàng Đô xem là một nỗi sỉ nhục đối với hắn.","nguon":["@c0314"]},{"id":"bao-vat-bi-an-che-giau-khi-the","name":"Bảo vật bí ẩn che giấu khí thế","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Nguyệt Thiền tiên tử"],"trangThai":"Đang được mang theo","blurb":"Pháp bảo chưa rõ tên có thể xóa bỏ khí thế của người mang, giúp Nguyệt Thiền tiên tử tránh khỏi linh giác của Thạch Hạo.","detail":"Bảo vật có khả năng khiến khí thế của người sử dụng biến mất, rất thích hợp để bí mật tiếp cận và tập kích những nhân vật thiên kiêu, khiến đối phương khó đề phòng.","nguon":["@c0315"]},{"id":"thiep-moi-mau-vang","name":"Thiệp mời màu vàng","cn":"","category":"khac","categoryLabel":"Tín vật thông hành","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Được sử dụng để vào hoàng cung","blurb":"Tấm thiệp dành cho khách quý, cho phép Thạch Hạo vào hoàng cung dự đại thọ Nhân Hoàng.","detail":"Thạch Hạo nhận được tấm thiệp mời màu vàng nhờ chiến tích gần đây và mối liên hệ với Nhân Hoàng. Đây là giấy thông hành để nó tiến vào hoàng cung trong ngày đại thọ.","nguon":["@c0316"]},{"id":"xich-lien","name":"Xích Liên","cn":"","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"","soHuu":[],"trangThai":"Sinh trưởng trong sông ngòi hoàng cung Thạch Quốc","blurb":"Linh dược nổi danh được trồng nhiều trong hoàng cung Thạch Quốc, vừa tạo cảnh quan vừa cung cấp nguyên liệu chế thuốc.","detail":"Xích Liên có toàn thân đỏ như lửa và hoa tỏa hương thơm. Khi trong cung cần chế thuốc, người ta sẽ hái loại linh dược này để sử dụng.","nguon":["@c0317"]},{"id":"thuong-co-thanh-khi-cua-thieu-nien-toc-xam","name":"Thượng Cổ Thánh khí của thiếu niên tóc xám","cn":"","category":"than-khi","categoryLabel":"Thánh khí","phamCap":"Thượng Cổ Thánh khí","soHuu":["Thiếu niên tóc xám mắt xám"],"trangThai":"Hoàn chỉnh, không hư tổn","blurb":"Thánh khí hoàn chỉnh được thiếu niên tóc xám kích hoạt để tập sát Thạch Hạo tại diễn võ trường Hoàng cung.","detail":"Binh khí tỏa hào quang trấn áp khiến trận văn của diễn võ trường rung chuyển. Uy lực của nó có thể nghiền chết tu sĩ Hóa Linh cảnh và được Thạch Hạo suy đoán là vật tổ truyền do trưởng bối Thần Sơn ban xuống.","nguon":["@c0318"]},{"id":"khi-hon-ho-ti-thien-than-son","name":"Khí hồn hộ tí Thiên Thần sơn","cn":"","category":"phap-bao","categoryLabel":"Pháp khí Thần Linh","phamCap":"Pháp khí Thần Linh","soHuu":["Thạch Hạo"],"trangThai":"Khí hồn không hoàn chỉnh, dung hợp với cánh tay trái của Thạch Hạo","blurb":"Khí hồn của hộ tí Thiên Thần sơn được Thạch Hạo lấy từ Hư Thần giới, có khả năng bảo vệ cơ thể và tăng cường sức mạnh cánh tay trái.","detail":"Khí hồn đã hòa sâu vào máu thịt cánh tay trái của Thạch Hạo, phát ra phù văn và khí tức thần thánh bao phủ toàn thân. Tuy không có thực thể hoàn chỉnh, nó vẫn đủ sức nhiều lần đánh bật Thanh Thiên bảo luân, nhưng chưa thể đánh tan món Thượng Cổ Thánh khí này.","nguon":["@c0319"]},{"id":"tam-da-hu-khong-thu","name":"Tấm da Hư Không thú","cn":"","category":"khac","categoryLabel":"Vật phẩm không gian","phamCap":"Không rõ","soHuu":["Hỏa Linh Nhi"],"trangThai":"Vẫn còn","blurb":"Vật phẩm do Hỏa Hoàng ban, có thể giúp người sử dụng lẩn vào hư không.","detail":"Hỏa Linh Nhi đề nghị Thạch Hạo dùng tấm da này lẩn vào hư không và bí mật rời khỏi Hoàng Đô để tránh cuộc quyết chiến với hai tôn giả, nhưng cậu từ chối bỏ trốn.","nguon":["@c0320"]},{"id":"ho-ti-cua-than","name":"Hộ tí của Thần","cn":"","category":"than-khi","categoryLabel":"Hộ tí","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được Thạch Hạo giữ","blurb":"Hộ tí có khả năng bảo vệ tính mạng của người sử dụng.","detail":"Khi Vân Hi và Ngân Tuyết tới gặp, Thạch Hạo cho biết mình vẫn cần sử dụng hộ tí để bảo vệ mạng sống và không định giao lại nếu việc đó khiến cậu có nguy cơ bị mưu sát.","nguon":["@c0320"]},{"id":"than-hanh-phu","name":"Thần Hành phù","cn":"","category":"khac","categoryLabel":"Phù","phamCap":"Không rõ","soHuu":["Vân Hi"],"trangThai":"Được Vân Hi dùng làm vật trao đổi","blurb":"Một tấm phù có thể giúp người sử dụng nhanh chóng chạy trốn.","detail":"Vân Hi đề nghị giao Thần Hành phù cho Thạch Hạo để đổi lấy hộ tí, đồng thời khuyên hắn dùng nó rời khỏi cuộc đối đầu với hai tôn giả.","nguon":["@c0321"]},{"id":"than-dan","name":"Thần đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"Chưa được luyện chế","blurb":"Một loại đan dược có Ma Chu thuần huyết làm chủ dược.","detail":"Thạch Hạo định giữ lại Ma Chu thuần huyết để làm chủ dược luyện Thần đan. Dược liệu cần được xử lý độc tính trước khi sử dụng.","nguon":["@c0321"]},{"id":"trung-uong-thien-cung","name":"Trung ương Thiên cung","cn":"","category":"khac","categoryLabel":"Kiến trúc hoặc pháp khí","phamCap":"Chưa xác định","soHuu":[],"trangThai":"Bản chất chưa xác định","blurb":"Trung ương Thiên cung có thể cùng toàn bộ quảng trường ở Hoàng thành bay lên, vượt hư không và giáng xuống giáo quân tràng.","detail":"Chưa rõ việc dịch chuyển là thủ đoạn của Thạch Hoàng hay do bản thân Trung ương Thiên cung là một pháp khí có năng lực vượt hư không. Khi Thiên cung cùng quảng trường tới giáo quân tràng, những người hiện diện và Thái Cổ Ma Chu cũng bị đưa theo.","nguon":["@c0323"]},{"id":"than-dai","name":"Thần đài","cn":"","category":"phap-bao","categoryLabel":"Pháp lực hiển hóa","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Do Tiểu tháp hiển hóa","blurb":"Một tòa thần đài xuất hiện dưới chân Thạch Hạo, nâng đỡ cậu giữa biển thần lực màu vàng.","detail":"Thần đài do Tiểu tháp hiển hóa, nâng đỡ Thạch Hạo rồi khuếch tán vô tận gợn sóng màu vàng và thần lực mênh mông. Sức mạnh này đánh tan thần hà của Thanh Loan tôn giả và cuốn đối phương vào trong.","nguon":["@c0324"]},{"id":"thanh-thien-bao-luan","name":"Thanh Thiên bảo luân","cn":"","category":"phap-bao","categoryLabel":"Thánh khí","phamCap":"Thánh khí","soHuu":["Thanh Loan tôn giả"],"trangThai":"Bị Tiểu tháp nuốt mất","blurb":"Thánh khí được Thanh Loan tôn giả thúc động để phát ánh sáng công kích Thạch Hạo và Tiểu tháp.","detail":"Thanh Thiên bảo luân phát ra ánh sáng nhằm hủy diệt một người một tháp, nhưng biến mất hoàn toàn ngay khi chạm vào Tiểu tháp.","nguon":["@c0324"]},{"id":"nguyen-thuy-chan-vu-thanh-loan","name":"Nguyên thủy chân vũ của Thanh Loan","cn":"","aliases":["Cọng linh vũ Thanh Loan"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Nguyên thủy chân vũ","soHuu":["Thạch Hạo"],"trangThai":"Nguyên vẹn","blurb":"Cọng linh vũ tinh túy của Thanh Loan, chứa nguyên thủy phù văn và có thể phát ra kiếm khí bá đạo khi vung lên.","detail":"Cọng lông duy nhất còn lại sau khi tiểu tháp luyện hóa thi thể Thanh Loan. Nó sinh trưởng cùng xương, liên kết với nguyên thủy phù cốt và giống như một bảo cụ trời sinh. Cọng lông nhẹ như không, phản phác quy chân, có thể phát ra kiếm khí đủ sức chém nát bảo cụ và là một trong năm loại nguyên thủy chân vũ cần để luyện chế quạt Ngũ Cầm.","nguon":["@c0325"]},{"id":"quat-ngu-cam","name":"Quạt Ngũ Cầm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đại sát khí Thượng Cổ","soHuu":[],"trangThai":"Chưa được luyện chế","blurb":"Đại sát khí thời Thượng Cổ được luyện từ nguyên thủy chân vũ của năm loại chim thần, có uy lực hủy diệt núi sông.","detail":"Quạt Ngũ Cầm là đại sát khí chấn động cổ kim, được nhắc cùng hàng với Túi Càn Khôn và Chén Hóa Thiên. Chỉ một lần vỗ nhẹ có thể biến núi cao thành tro bụi và sấy khô sông hồ. Việc luyện chế cần năm loại nguyên thủy chân vũ của năm loài chim thần; lông chim thông thường có thể thay thế nhưng khiến uy lực suy giảm. Phương pháp luyện chế được ghi lại trong các đại giáo.","nguon":["@c0325"]},{"id":"than-nhuong-cuu-long","name":"Thần nhưỡng Cửu Long","cn":"","category":"khac","categoryLabel":"Linh tửu","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Đã được Thạch Hạo uống; phần dược lực còn lại được phong kín trong máu thịt","blurb":"Linh tửu màu xanh do Nhân Hoàng ban cho Thạch Hạo, chứa dược lực từ linh dược và thánh dược.","detail":"Một ly Thần nhưỡng Cửu Long cung cấp sinh cơ và dược lực mạnh mẽ, thúc đẩy Thạch Hạo từ Hóa Linh viên mãn tiến sát Minh Văn cảnh. Vì chưa muốn đột phá, hắn chủ động trấn áp, hấp thu một phần và phong kín phần dược lực còn lại trong máu thịt để dùng khi chính thức bước sang cảnh giới tiếp theo.","nguon":["@c0326"]},{"id":"long-giac-tien-mau-vang","name":"Long Giác tiễn màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Nguyên vẹn","blurb":"Pháp khí màu vàng được Thạch Hạo dùng để cắt phá lớp xích vũ cứng rắn của hung cầm biến dị.","detail":"Long Giác tiễn có khả năng cắt đứt lớp xích vũ của con hung cầm sống trong ao dung nham tại tổ địa Hỏa tộc.","nguon":["@c0329"]},{"id":"hoa-sen-xanh","name":"Hoa sen xanh","cn":"","category":"nguyen-lieu","categoryLabel":"Dị thảo","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Sinh trưởng trong hồ dung nham","blurb":"Dị thảo hấp thu vật chất thần tính, có thể bù đắp nhiều tháng tu hành.","detail":"Hoa sen xanh cắm rễ trong khe đá rồi tiếp tục tồn tại giữa hồ dung nham. Trong quá trình hấp thu vật chất thần tính, nó dần xuất hiện ánh sáng trắng bạc và trở thành mục tiêu tranh đoạt của nhiều tu sĩ.","nguon":["@c0329"]},{"id":"than-phu","name":"Thần phủ","cn":"","category":"khac","categoryLabel":"Cung điện tu hành Thượng Cổ","phamCap":"Thượng Cổ","soHuu":[],"trangThai":"Xuất thế dưới hồ dung nham","blurb":"Cung điện tu hành từ thời Thượng Cổ có thể hỗ trợ ngộ đạo, rút ngắn thời gian khổ tu và có khả năng lưu giữ truyền thừa.","detail":"Thần phủ nằm dưới đáy hồ dung nham tại tổ địa Hỏa tộc. Phù văn của nó tạo nên đợt dung nham bùng phát trong khu vực; khi mở ra, nơi này thu hút hàng chục tu sĩ đến tranh đoạt vì khả năng hỗ trợ tu hành và tiềm năng lưu giữ pháp môn Thượng Cổ. Thần phủ chỉ tồn tại trong một khoảng thời gian hữu hạn trước khi sụp đổ.","nguon":["@c0329"]},{"id":"den-dong-co","name":"Đèn đồng cổ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí bình thường","soHuu":["Thạch Hạo"],"trangThai":"Được cất trong túi càn khôn","blurb":"Một chiếc đèn đồng cổ phủ bụi, bản thân chỉ là pháp khí bình thường nhưng còn lưu giữ thần huyết dưới tim đèn.","detail":"Đèn có khắc phù văn và đã tồn tại từ thời xa xưa. Chất lỏng gần khô dưới tim đèn chứa thần năng đáng sợ; Thạch Hạo lấy tim đèn ra, kiểm tra kỹ rồi thu cả chiếc đèn vào túi càn khôn.","nguon":["@c0330"]},{"id":"than-huyet-trong-den-dong","name":"Thần huyết trong đèn đồng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thần huyết","soHuu":["Thạch Hạo"],"trangThai":"Gần khô cạn, được cất giữ","blurb":"Phần thần huyết còn sót lại dưới tim đèn đồng, tuy gần khô cạn nhưng thần tính vẫn chưa tiêu tan.","detail":"Thần huyết không còn tỏa hào quang nhưng vẫn chứa thần năng mạnh mẽ, khiến người đến gần run sợ và khó hô hấp. Thạch Hạo không sử dụng ngay mà cất đi để dành cho thời điểm thích hợp.","nguon":["@c0330"]},{"id":"hoa-sen-trang-bac","name":"Hoa sen trắng bạc","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Linh dược","phanLoaiPhu":"Linh dược chứa thần tính","phamCap":"Chưa xác định","soHuu":["Thạch Hạo"],"trangThai":"Đã được ăn và luyện hóa","blurb":"Cây hoa sen chuyển từ xanh lam sang trắng bạc sau khi được hồ dung nham tẩm bổ, bên trong chứa sức mạnh thần tính mạnh hơn linh dược bình thường.","detail":"Thạch Hạo ăn hoa sen rồi luyện hóa dược lực mãnh liệt của nó. Để tránh bị đẩy thẳng vào Minh Văn cảnh trước khi phá cực cảnh Hóa Linh, nó phong ấn sức mạnh thu được vào huyết nhục và xương cốt.","hinhDang":"Hoa sen có màu trắng bạc, trước đó mang màu xanh lam.","nguonGoc":"Được hồ dung nham tẩm bổ.","uyLuc":"Cung cấp một lượng sức mạnh thần tính mãnh liệt cho người dùng.","dacDiem":"Màu sắc chuyển từ xanh lam sang trắng bạc sau khi được hồ dung nham nuôi dưỡng.","chuHienThoi":"Thạch Hạo","congNang":["Bổ sung sức mạnh thần tính cho người dùng."],"chuSoHuu":[{"ten":"Thạch Hạo","tuChuong":"@c0331","denChuong":"@c0331","cachCoDuoc":"Thu lấy trong khu vực đại điện ngộ đạo rồi ăn và luyện hóa.","trangThai":"Đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0331","loai":"dùng","importance":"normal","giaiDoan":"Được luyện hóa","text":"Thạch Hạo ăn hoa sen trắng bạc, luyện hóa rồi phong ấn dược lực vào huyết nhục và xương cốt.","anchor":"có sức mạnh của thần tính được thai nghén ở bên trong"}]},"capNhatToi":"@c0331","nguon":["@c0331"]},{"id":"cung-lon-nau-xam","name":"Cung lớn nâu xám","cn":"","category":"phap-bao","categoryLabel":"Cung","phanLoaiPhu":"Cung pháp khí","phamCap":"Không rõ","soHuu":["Thiếu niên tóc vàng"],"trangThai":"Đang được sử dụng","blurb":"Một cây cung nâu xám già cũ do thiếu niên tóc vàng sử dụng. Khi kéo dây, cây cung hiện ra uy thế giao long và bắn những mũi tên mang thần lực mạnh mẽ.","detail":"Dây cung óng ánh và hóa thành hình ảnh giao long thét dài khi được kéo căng. Thiếu niên tóc vàng dùng cây cung này bắn liên tiếp ba mũi tên nhằm vào Thạch Hạo.","hinhDang":"Cây cung lớn màu nâu xám, mang vẻ già cũ.","dacDiem":"Dây cung hiện dị tượng giao long khi được kéo.","chuHienThoi":"Thiếu niên tóc vàng","uyLuc":"Có thể bắn mũi tên mang thần lực đủ sức phá quang thuẫn và hình thái Toan Nghê.","congNang":["Bắn mũi tên mang thần lực mạnh.","Truyền sức mạnh lôi điện của người sử dụng vào mũi tên."],"chuSoHuu":[{"ten":"Thiếu niên tóc vàng","tuChuong":"@c0332","denChuong":"","cachCoDuoc":"","trangThai":"Đang sở hữu"}],"capNhatToi":"@c0332","tabs":{"tienTrinh":[{"chuong":"@c0332","loai":"dùng","importance":"normal","giaiDoan":"Phục kích Thạch Hạo","text":"Thiếu niên tóc vàng dùng cung nâu xám bắn ba mũi tên hoàng kim có uy lực tăng dần về phía Thạch Hạo.","anchor":"dây cung óng ánh hóa thành một con giao long thét dài nơi đó","phamCap":"Không rõ"}]},"nguon":["@c0332"]},{"id":"mui-ten-hoang-kim","name":"Mũi tên hoàng kim","cn":"","category":"phap-bao","categoryLabel":"Tiễn pháp khí","phamCap":"Không rõ","soHuu":["Thiếu niên tóc vàng"],"trangThai":"Các mũi tên đã bị phá hủy","blurb":"Tiễn pháp khí màu vàng được thiếu niên tóc vàng dùng để phục kích Thạch Hạo. Mũi tên có thể quay lại truy kích và chuyên chở thần lực cùng lôi điện.","detail":"Thiếu niên tóc vàng liên tiếp bắn ba mũi tên với uy lực tăng dần. Chúng lần lượt bị quang thuẫn và Bảo thuật Toan Nghê tiêu hao, bị quyền mang phù văn Toan Nghê đánh gãy, hoặc bị đạo thần hi hóa chuông nghiền nát.","hinhDang":"Mũi tên phát ra thần mang vàng chói.","uyLuc":"Có thể phá quang thuẫn, xuyên qua hình thái Toan Nghê và làm nổ gò đất.","dacDiem":"Có thể đổi hướng quay lại truy kích mục tiêu và mang theo sức mạnh lôi điện.","chuHienThoi":"Thiếu niên tóc vàng","congNang":["Quay ngược để tiếp tục truy kích mục tiêu.","Chuyên chở thần lực và sức mạnh lôi điện của người bắn."],"chuSoHuu":[{"ten":"Thiếu niên tóc vàng","tuChuong":"@c0332","denChuong":"@c0332","cachCoDuoc":"","trangThai":"Đã sử dụng"}],"capNhatToi":"@c0332","tabs":{"tienTrinh":[{"chuong":"@c0332","loai":"dùng","importance":"normal","giaiDoan":"Ba lần công kích","text":"Thiếu niên tóc vàng liên tiếp bắn các mũi tên hoàng kim có khả năng truy kích và mang lôi điện, nhưng tất cả đều bị Thạch Hạo phá hủy.","anchor":"thần mang vàng óng bay trở lại rồi bắn về phía Thạch Hạo","phamCap":"Không rõ"}]},"nguon":["@c0332"]},{"id":"cung-phong-loi-giao","name":"Cung Phong Lôi Giao","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ trường cung","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Đã đổi chủ","blurb":"Bảo cụ trường cung của thiếu niên tóc vàng thuộc Phong Lôi Vũ tộc, sau đó bị Thạch Hạo đoạt lấy.","detail":"Cây cung bắn ra luồng tên vàng dài khoảng mười mét, có thể xuyên phá biển đen và khiên Huyền Vũ. Sau khi giết chủ cũ, Thạch Hạo dùng cung bắn hạ toàn bộ đám tôi tớ tới cứu viện; bảo cụ này sau đó còn khiến hai thiên tài dị tộc tìm đến tranh đoạt.","nguon":["@c0333"]},{"id":"den-bac","name":"Đèn bạc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Một trong bốn lão giả phạm giới"],"trangThai":"Đang được sử dụng","blurb":"Bảo cụ phóng ra ánh lửa màu bạc có sức nóng dữ dội, đủ sức nung đá lớn thành dung nham.","detail":"Một trong bốn lão giả phạm giới dùng chiếc đèn này tập kích Thạch Hạo tại tổ địa Hỏa tộc. Ánh lửa bạc từ đèn trút xuống như thác nước, quét qua đâu liền nung chảy đá lớn thành dung nham.","nguon":["@c0334"]},{"id":"co-lon-cua-lao-gia-pham-gioi","name":"Cờ lớn của lão giả phạm giới","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Một trong bốn lão giả phạm giới"],"trangThai":"Đang được sử dụng","blurb":"Bảo cụ có thể làm rạn nứt mặt đất và giải phóng khói đen ngập trời.","detail":"Một lão giả trong nhóm phạm giới vung lá cờ này khi truy kích Thạch Hạo. Uy lực của cờ khiến cả khu sa mạc bắt đầu rạn nứt, đồng thời tạo ra khói đen dày đặc lan tràn về phía mục tiêu.","nguon":["@c0334"]},{"id":"kinh-van-co","name":"Kinh văn cổ","cn":"","category":"khac","categoryLabel":"Kinh thư","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Liên tục đổi chủ","blurb":"Một tờ kinh văn xuất hiện sâu trong tổ địa Hỏa tộc, kéo theo cuộc tranh đoạt đẫm máu và nhiều lần đổi chủ.","detail":"Những người từng chiếm được kinh văn đều lần lượt thiệt mạng, khiến nơi tranh đoạt nhuộm máu. Kinh văn vẫn tiếp tục chuyển từ chủ nhân này sang chủ nhân khác giữa cuộc tranh giành chưa ngã ngũ.","nguon":["@c0334"]},{"id":"to-kinh-thu-bang-dong","name":"Tờ kinh thư bằng đồng","cn":"","category":"khac","categoryLabel":"Kinh thư","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Nguyên vẹn, được Thạch Hạo thu giữ","blurb":"Kinh thư bằng đồng lấy từ di vật của thiếu niên Viêm Mãng, ghi lại phương pháp giúp người dùng nhanh chóng tăng thực lực trong tổ địa.","detail":"Tờ kinh thư có tính dẻo, phát ra tiếng kim loại khi bị búng và không bị nước lửa làm hư hại. Nội dung trên bề mặt có thể giúp Thạch Hạo nhanh chóng tăng thực lực tại tổ địa, khiến nó được đánh giá là quý giá hơn cả việc đoạt được một môn đại thần thông.","nguon":["@c0335"]},{"id":"co-lon-mau-vang","name":"Cờ lớn màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Hỏa Hoàng"],"trangThai":"Đã phá huyết tế đại trận rồi tự bay đi","blurb":"Lá cờ vàng khổng lồ mang uy thế của Hỏa Hoàng, có khả năng phá trận và tạo ra gió vàng sát phạt.","detail":"Cờ từ trên cao giáng xuống, cắm vào huyết tế đại trận và khiến toàn bộ phù văn tan vỡ. Sau đó, cờ bay phần phật tạo thành gió vàng, chém đứt những Viêm Mãng đang hóa bản thể bỏ chạy rồi tự rời khỏi chiến trường.","nguon":["@c0335"]},{"id":"tang-da-mau-den","name":"Tảng đá màu đen","cn":"","category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"Chưa rõ","soHuu":["Các lão giả vực ngoại phá trận"],"trangThai":"Được dùng để cầu viện Hỏa Hoàng","blurb":"Vật phẩm màu đen được một lão giả vực ngoại sử dụng khi truyền tin tới Hỏa Hoàng.","detail":"Trong lúc huyết tế đại trận hoạt động, một lão giả vực ngoại cầm tảng đá trong tay, niệm thần chú và truyền lời báo rằng tộc Viêm Mãng đã vi phạm thỏa thuận, đe dọa làm tổn thương căn cơ Hỏa Quốc.","nguon":["@c0335"]},{"id":"phuong-thuoc-co-xua","name":"Phương thuốc cổ xưa","cn":"","category":"khac","categoryLabel":"Dược phương","phamCap":"Cổ phương","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Dược phương ghi cách luyện sinh linh giàu tinh hoa thần tính trong Hỏa vực thành vật chất giúp người dùng ngộ đạo, phá quan và lột xác.","detail":"Phương thuốc lấy sinh linh chứa vật chất thần tính làm chủ dược, kết hợp thêm dược liệu để luyện hóa và tinh lọc. Nội dung còn ghi những sinh linh quý hiếm có thể dùng, phương pháp bắt chúng và vật liệu thích hợp để dẫn dụ; Thạch Hạo hiện mới thử luyện chủ dược nên thành phẩm vẫn còn tạp chất.","nguon":["@c0336"]},{"id":"chat-long-than-tinh-mau-vang","name":"Chất lỏng thần tính màu vàng","cn":"","category":"dan-duoc","categoryLabel":"Tinh hoa luyện hóa","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Đã sử dụng","blurb":"Tinh hoa màu vàng được luyện từ huyết nhục của hung thú gần cấp vương hầu theo phương thuốc cổ xưa.","detail":"Chén Hóa Thiên và đạo hỏa luyện toàn bộ huyết nhục của trâu đen thành tro, chỉ giữ lại một giọt chất lỏng vàng óng có mùi thơm. Thành phẩm vẫn còn tạp chất, nhưng sau khi Thạch Hạo nuốt vào, toàn thân nó phát kim quang và khí tức mạnh lên.","nguon":["@c0336"]},{"id":"bot-cot-tuy-hung-thu","name":"Bột cốt tủy hung thú","cn":"","category":"nguyen-lieu","categoryLabel":"Mồi nhử","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Đã dùng làm mồi","blurb":"Bột nghiền từ cốt tủy của trâu đen và sư tử bạc, được dùng để dẫn dụ sinh linh thần tính sống trong dung nham.","detail":"Thạch Hạo giữ lại cốt tủy của hai hung thú mạnh, hong khô rồi nghiền thành bột. Khi được rắc xuống hồ dung nham, bột vẫn lấp lánh, không hóa thành tro và tỏa mùi thơm, thu hút đàn cá vàng có linh tính tới tranh nhau nuốt mồi.","nguon":["@c0336"]},{"id":"ca-mat-troi","name":"Cá mặt trời","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Gần trăm con đã bị bắt và luyện hóa","blurb":"Biến chủng quý hiếm của Hỏa Viêm Ngư, có toàn thân vàng óng và sinh sống trong hồ dung nham.","detail":"Cá mặt trời mang phù văn, có thể xuyên qua cấm chế và được cho là có khả năng sinh sống trong mặt trời. Thạch Hạo dùng chén Hóa Thiên bắt chúng, sau đó luyện gần trăm con thành chất lỏng màu vàng chứa vật chất thần tính để hỗ trợ tu luyện.","nguon":["@c0337"]},{"id":"chat-long-mau-vang-tu-ca-mat-troi","name":"Chất lỏng màu vàng từ Cá mặt trời","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đã được Thạch Hạo hấp thu","blurb":"Tinh hoa thần tính cô đọng sau khi luyện hóa Cá mặt trời, có tác dụng hỗ trợ tu luyện và ngộ đạo.","detail":"Mười tám con Cá mặt trời được luyện thành một giọt chất lỏng màu vàng. Sau khi bắt thêm gần trăm con và nuốt những giọt tinh hoa luyện được, Thạch Hạo trở nên tinh thần sung mãn, tiến vào trạng thái tâm linh không minh và thu được thành quả lớn khi ngộ pháp, ngộ đạo.","nguon":["@c0337"]},{"id":"bia-ky-luc-hu-than-gioi","name":"Bia kỷ lục Hư Thần giới","cn":"","category":"khac","categoryLabel":"Vật phẩm quy tắc","phamCap":"","soHuu":[],"trangThai":"Hiện ra khi có kỷ lục mới","blurb":"Bia đá công bố kỷ lục mới khắp Hư Thần giới, đồng thời hiển thị nội dung do người lập kỷ lục ghi lại.","detail":"Mỗi khi một kỷ lục bị phá, những tấm bia đá đồng bộ hiện lên khắp nơi để chiêu cáo thiên hạ. Thạch Hạo và Thạch Nghị liên tiếp lập kỷ lục rồi ghi lời chất vấn, khiêu khích và đáp trả lên bia, biến chúng thành phương tiện truyền lời giữa hai khu vực Hóa Linh và Minh Văn.","nguon":["@c0340"]},{"id":"tran-ky-to-khi-ho-ma-linh","name":"Trận kỳ tổ khí Hồ Ma Linh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tổ khí","soHuu":["Hồ Ma Linh"],"trangThai":"Đã rời bỏ nhện lớn màu xanh biếc và biến mất vào sâu trong cổ địa","blurb":"Tổ khí của Hồ Ma Linh có khả năng điều khiển đại trận Thần Linh và làm biến đổi khí tức cổ địa.","detail":"Trận kỳ được nhện lớn màu xanh biếc sử dụng để vận chuyển đại trận Thần Linh trấn áp Thạch Hạo. Sau khi tầng trận thứ nhất bị phá, tổ khí tự rời khỏi nhện xanh, rơi vào nơi sâu trong cổ địa rồi biến mất; chủ nhân mới chưa được xác định.","nguon":["@c0341"]},{"id":"diet-hon-cham","name":"Diệt Hồn châm","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Đang được Thạch Hạo sử dụng","blurb":"Pháp khí công kích thần hồn, có thể thông qua thân thể trong Hư Thần giới gây thương tổn tới bản thể ngoài hiện thực.","detail":"Thạch Hạo đâm Diệt Hồn châm vào màn mưa ánh sáng do thi thể nhện xanh tan thành, khiến đầu bản thể của đối phương tại Hồ Ma Linh ngoài hiện thực nổ tung và rơi vào tình trạng gần chết.","nguon":["@c0341"]},{"id":"phap-khi-cua-nhen-vang","name":"Pháp khí của nhện vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"","soHuu":["Nhện màu vàng Hồ Ma Linh"],"trangThai":"Đang được nhện màu vàng sử dụng","blurb":"Pháp khí được dùng để trấn áp thương thế và ổn định phần đầu bị nổ của nhện xanh ngoài thế giới hiện thực.","detail":"Khi thương tổn từ Diệt Hồn châm truyền tới bản thể nhện xanh, nhện màu vàng lấy pháp khí này ra trấn áp thương thế, ổn định phần đầu của đối phương và hỗ trợ giữ lại một luồng thần hồn.","nguon":["@c0341"]},{"id":"con-mat-than-nhan-trung-dong","name":"Con mắt thần nhân Trùng Đồng","cn":"","category":"khac","categoryLabel":"Dị vật","phamCap":"Mắt của thần nhân đã chết","soHuu":["Thạch Hạo"],"trangThai":"Đang được Thạch Hạo sử dụng","blurb":"Một con mắt Trùng Đồng của thần nhân đã chết, có thể phát ra thần uy dưới sự điều khiển của Thạch Hạo.","detail":"Thạch Hạo thường điều khiển con mắt này để đánh người. Theo Thạch Nghị, do đã trở thành vật chết nên nó chỉ có thể phát huy một hai phần uy thế vốn có.","nguon":["@c0342"]},{"id":"kim-than-dich","name":"Kim Thân dịch","cn":"","category":"dan-duoc","categoryLabel":"Bảo dịch","phamCap":"Thần dịch vô giá của Bổ Thiên giáo","soHuu":["Thạch Nghị"],"trangThai":"Đã được sử dụng","blurb":"Bảo dịch danh chấn thiên hạ của Bổ Thiên giáo, có công dụng gột rửa thân thể và giúp người sử dụng đạt tới thân thể bất phôi.","detail":"Kim Thân dịch vô cùng quý giá, mỗi đời chỉ có một số ít nhân vật chính thống của Bổ Thiên giáo được sử dụng. Thạch Nghị được nhận ra là đã trải qua sự gột rửa bằng thần dịch này, khiến thân thể có sắc vàng nhạt lưu chuyển và đủ sức đối kháng trực diện với thân thể cực cảnh của Thạch Hạo.","nguon":["@c0342","@c0370"]},{"id":"kim-cuong-dich","name":"Kim Cương dịch","cn":"","category":"dan-duoc","categoryLabel":"Bảo dịch","phamCap":"Bảo dịch danh chấn thiên hạ của Tây Thiên giáo","soHuu":[],"trangThai":"Chưa ghi nhận người sử dụng trong chương này","blurb":"Bảo dịch nổi danh của Tây Thiên giáo, có thể gột rửa thân thể và giúp người sử dụng sở hữu thân thể bất phôi.","detail":"Thiên Hồ tiên tử từng cho rằng thân thể mạnh mẽ của Thạch Hạo có thể đến từ Kim Cương dịch, nhưng sau đó xác định sức mạnh ấy do chính hắn tu thành chứ không nhờ bảo dịch gột rửa.","nguon":["@c0342"]},{"id":"than-thu-dong-thau","name":"Thần thư đồng thau","cn":"","category":"khac","categoryLabel":"Thần thư","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Chưa rõ","blurb":"Một thần thư có giá trị cao, được người Vũ tộc dùng làm chuẩn so sánh với phần thưởng thần bí của Thạch Nghị.","detail":"Giá trị của phần thưởng thần bí từng dành cho Thạch Nghị được đánh giá là không kém Thần thư đồng thau.","nguon":["@c0344"]},{"id":"phan-thuong-than-bi-cua-thach-nghi","name":"Phần thưởng thần bí của Thạch Nghị","cn":"","category":"khac","categoryLabel":"Phần thưởng kỷ lục","phamCap":"Chưa rõ","soHuu":["Thạch Nghị"],"trangThai":"Chưa nhận","blurb":"Phần thưởng gắn với kỷ lục cũ của Thạch Nghị, được đánh giá có giá trị không kém Thần thư đồng thau.","detail":"Thạch Nghị chỉ có thể nhận phần thưởng này nếu chiến thắng đối thủ tại chiến trường Thiên Không.","nguon":["@c0344"]},{"id":"phan-thuong-tich-luy-cua-thach-hao","name":"Phần thưởng tích lũy của Thạch Hạo","cn":"","category":"khac","categoryLabel":"Phần thưởng kỷ lục","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang tích lũy","blurb":"Phần thưởng được tích lũy từ nhiều kỷ lục mới của Thạch Hạo tại Hư Thần giới.","detail":"Toàn bộ phần thưởng kỷ lục của Thạch Hạo có thể được tích lũy, nhưng chỉ được ban sau khi cậu chiến thắng tại chiến trường Thiên Không.","nguon":["@c0344"]},{"id":"dan-duoc-thom-ngat-cua-hoa-linh-nhi","name":"Đan dược thơm ngát của Hỏa Linh Nhi","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Chưa rõ","soHuu":["Hỏa Linh Nhi"],"trangThai":"Đã được Thạch Hạo sử dụng","blurb":"Viên đan dược thơm ngát được Hỏa Linh Nhi đưa cho Thạch Hạo để chữa thương sau cuộc giao chiến với Thạch Nghị.","detail":"Viên đan dược phát sáng, có ký hiệu kỳ dị và giúp thương thế của Thạch Hạo nhanh chóng hồi phục. Sau khi uống, cơ thể nó vang lên như rồng ngâm hổ gầm và sắc mặt dần hồng hào trở lại.","nguon":["@c0345"]},{"id":"phu-than-cua-hoa-hoang","name":"Phủ thần của Hỏa Hoàng","cn":"","category":"khac","categoryLabel":"Phủ đệ tu luyện","phamCap":"Phủ thần","soHuu":["Thạch Hạo"],"trangThai":"Đã nổ tung sau khi Thạch Hạo lĩnh ngộ bảo thuật Côn Bằng","blurb":"Phủ thần do Hỏa Hoàng ban cho Thạch Hạo, có khả năng nâng cao mạnh mẽ hiệu quả tu hành và hỗ trợ ngộ đạo.","detail":"Tòa phủ ẩn hiện trong dung nham, lưu chuyển hào quang vàng nhạt và vang tiếng tụng kinh. Một ngày tu hành bên trong có thể tương đương nhiều chục đến cả trăm ngày ở ngoại giới; khi Thạch Hạo lĩnh ngộ thấu đáo bảo thuật Côn Bằng, khí tức bùng phát khiến cung điện rạn nứt rồi nổ tung.","nguon":["@c0346"]},{"id":"bo-doan-go-con","name":"Bồ đoàn gỗ Côn","cn":"","category":"phap-bao","categoryLabel":"Bảo vật ngộ đạo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được Thạch Hạo sử dụng","blurb":"Bồ đoàn đan từ gỗ Côn mà Thạch Hạo lấy được tại sào huyệt Côn Bằng, có tác dụng hỗ trợ tiến vào cảnh giới ngộ đạo.","detail":"Khi được sử dụng trong phủ thần của Hỏa Hoàng, bồ đoàn lượn lờ âm thanh cổ kinh và làm hiệu quả ngộ đạo tăng lên rõ rệt, giúp Thạch Hạo thể ngộ đại đạo Côn Bằng.","nguon":["@c0346"]},{"id":"kinh-van-bat-ca-mat-troi","name":"Tờ kinh văn bắt Cá mặt trời","cn":"","category":"khac","categoryLabel":"Kinh văn","phamCap":"Chưa xác định","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Tờ kinh văn ghi lại phương pháp phối hợp nhiều sinh linh mạnh làm mồi để săn bắt Cá mặt trời.","detail":"Kinh văn hướng dẫn luyện chung nhiều loại sinh linh mạnh thành mồi, cho hiệu quả tốt hơn việc chỉ rút lấy xương tủy riêng lẻ. Thạch Hạo dựa vào phương pháp này để thu thập và phối hợp các con mồi trước khi thả xuống hồ dung nham.","nguon":["@c0347"]},{"id":"hon-da-do-vat-chat-than-tinh","name":"Hòn đá đỏ chứa vật chất thần tính","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu thần tính","phamCap":"Chưa xác định","soHuu":["Bạch Giáp Vương"],"trangThai":"Bị Bạch Giáp Vương luyện hóa","blurb":"Hòn đá màu đỏ chứa vật chất thần tính có giá trị cao, từng được Bạch Giáp Vương dùng làm mồi nhử đối thủ.","detail":"Bạch Giáp Vương giả vờ nuốt hòn đá để dụ một nhóm cường giả ra tay tranh đoạt. Sau khi giết sạch đối phương, nó nhả hòn đá ra và bắt đầu luyện hóa vật chất thần tính bên trong.","nguon":["@c0347"]},{"id":"lo-do-ruc","name":"Lò đỏ rực","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"","soHuu":["Các tu sĩ Hóa Linh hậu kỳ của tộc một sừng"],"trangThai":"Đã bị phá hủy","blurb":"Bảo cụ do nhiều tu sĩ Hóa Linh hậu kỳ hợp lực điều khiển để trấn áp Thạch Hạo.","detail":"Chiếc lò phóng ra từng chùm lửa mang khí tức đáng sợ. Cá thần màu đen do bảo thuật Côn Bằng hóa thành vẫy đuôi đánh nổ bảo cụ này.","nguon":["@c0348"]},{"id":"phap-khi-giam-giu-tu-binh","name":"Pháp khí giam giữ tù binh","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Pháp khí dùng để phong ấn và giam giữ ba tù binh vực ngoại trước cuộc thẩm vấn.","detail":"Thạch Hạo giữ thiếu niên một sừng, người trẻ tuổi tộc bốn mắt và thiếu nữ Phiêu Miểu cung trong pháp khí này. Sau khi kết thúc tu luyện, nó thả cả ba người đang bị phong ấn ra để tra hỏi tin tức về vực ngoại.","nguon":["@c0349"]},{"id":"qua-trung-do-trung-chu-tuoc-niet-ban","name":"Quả trứng đỏ","cn":"","aliases":["Trứng Chu Tước niết bàn"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã nở, vỏ trứng bị nuốt hết","blurb":"Quả trứng đỏ đậm chứa Tiểu Hồng trong quá trình niết bàn tái sinh, mang sinh cơ mãnh liệt và nhiệt độ đủ sức nấu chảy bảo cụ.","detail":"Quả trứng to bằng nắm đấm, đỏ đậm như kim cương máu và phủ dày phù văn. Nó tỏa ra hơi thở sinh mệnh vượt xa những quả trứng Thạch Hạo từng gặp, chứa mảnh vỡ đại đạo và phát ra nhiệt lượng có thể nấu chảy bảo cụ. Sau khi được Thạch Hạo dùng phù văn tác động trong chén Hóa Thiên, trứng nở thành Tiểu Hồng; con chim đỏ nhỏ nuốt sạch phần vỏ còn lại.","nguon":["@c0350"]},{"id":"to-chim-vang","name":"Tổ chim vàng","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tiểu Hồng"],"trangThai":"Còn trên ngọn cây cổ thụ","blurb":"Tổ chim hình cầu vàng óng nằm trên ngọn cây cổ thụ, là nơi cất giữ quả trứng niết bàn của Tiểu Hồng.","detail":"Tổ được bện từ những cành cây kỳ dị óng ánh và thơm ngát, có thể là cành Thánh thụ. Kết cấu của tổ đóng kín như tổ chim Khách, chỉ chừa một lỗ rộng bằng nắm tay; bên trong từng chứa quả trứng đỏ của Tiểu Hồng.","nguon":["@c0350"]},{"id":"nguyen-thuy-chan-vu-chu-tuoc","name":"Nguyên thủy chân vũ Chu Tước","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thần vũ","soHuu":[],"trangThai":"Có thể còn một cọng trong Thánh Hoàng cung","blurb":"Thần vũ duy nhất nối liền với nguyên thủy phù cốt của một cá thể Chu Tước trước khi thành chân Thần.","detail":"Mỗi cá thể trước khi trở thành chân Thần cả đời chỉ có một chiếc lông như vậy. Thạch Hạo muốn tìm chân vũ để tế luyện Quạt Ngũ Cầm; Tiểu Hồng điểu tiết lộ trong Thánh Hoàng cung có thể vẫn còn một cọng Chu Tước chân vũ.","nguon":["@c0351"]},{"id":"linh-vu-cua-tieu-hong","name":"Linh vũ của Tiểu Hồng","cn":"","category":"nguyen-lieu","categoryLabel":"Thần vũ","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đã được Tiểu Hồng điểu trao cho Thạch Hạo","blurb":"Một cọng linh vũ do Tiểu Hồng điểu từng trao cho Thạch Hạo.","detail":"Tiểu Hồng điểu xem cọng linh vũ này là món quà có giá trị, trong khi Thạch Hạo chê nó cụt ngủn.","nguon":["@c0351"]},{"id":"tia-lua-than","name":"Tia lửa Thần","cn":"","category":"khac","categoryLabel":"Thần vật","phamCap":"Không rõ","soHuu":[],"trangThai":"Được Hỏa Hoàng hứa trao cho Tiểu Hồng điểu","blurb":"Thần vật được Hỏa Hoàng dùng làm điều kiện thương lượng với Tiểu Hồng điểu.","detail":"Hỏa Hoàng hứa trao một tia lửa Thần để Tiểu Hồng điểu cân nhắc cho Hỏa Linh Nhi tiến vào Thánh Hoàng cung.","nguon":["@c0351"]},{"id":"chuong-lon-mau-do-tham","name":"Chuông lớn màu đỏ thẫm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang bảo vệ kinh cổ trên đạo đài màu đỏ","blurb":"Một chiếc chuông đỏ thẫm bao phủ kinh cổ, phát ra tiếng chuông và phù văn huyền bí để bảo vệ truyền thừa.","detail":"Khi Thạch Hạo đánh trúng chuông, pháp bảo phát ra sóng lửa và khí tức đại đạo bá đạo, đẩy văng người khiêu chiến. Thạch Hạo phải vận dụng bảo thuật Côn Bằng cùng sức mạnh Mặt Trăng để hóa giải lực phản chấn.","nguon":["@c0354"]},{"id":"bo-doan-truyen-thua","name":"Bồ đoàn truyền thừa","cn":"","category":"khac","categoryLabel":"Vật phẩm tu hành","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang được dùng để tiếp nhận truyền thừa","blurb":"Bồ đoàn trong Thánh Hoàng cung có thể dẫn người hữu duyên vào quá trình tiếp nhận và củng cố truyền thừa.","detail":"Bồ đoàn tự hút Hỏa Linh Nhi lên ngồi, phát ra phù văn cùng âm thanh như bậc trưởng bối dạy bảo hậu bối. Nó đồng thời dẫn động kinh cổ xuất hiện trên đầu nàng và cộng hưởng với dấu ấn Chu Tước tại mi tâm.","nguon":["@c0354"]},{"id":"bia-da-san-dau","name":"Bia đá sân đấu","cn":"","category":"khac","categoryLabel":"Vật ghi truyền thừa","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang hiện diện bên sân đấu đá đen","blurb":"Tấm bia đá ghi lại quy tắc khiêu chiến dành cho cường giả không thuộc Hỏa tộc và phần thưởng của cửa ải.","detail":"Văn bia trình bày nguồn gốc cùng yêu cầu tu luyện Bốn kích của Thái Cổ Chu Tước. Nội dung cho biết pháp môn chưa hoàn chỉnh này đòi hỏi thể phách sánh ngang Thái Cổ Chu Tước; nếu thôi diễn đủ mười kích thì có thể tái hiện bảo thuật Chu Tước vô thượng.","nguon":["@c0354"]},{"id":"chat-long-niet-ban","name":"Chất lỏng niết bàn","cn":"","category":"nguyen-lieu","categoryLabel":"Thần tính vật chất","phamCap":"","soHuu":[],"trangThai":"Tồn tại trong hồ Niết Bàn","blurb":"Tinh hoa do Thái Cổ Chu Tước lưu lại khi niết bàn, có thể hỗ trợ người sử dụng niết bàn và lột xác mạnh mẽ.","detail":"Chất lỏng đỏ thẫm mang ánh vàng nhạt và hương thơm, nhỏ từ hư không xuống hai hồ dung nham. Nó tinh thuần hơn vật chất thần tính lấy từ Cá mặt trời và từng giúp các đời tiên hiền Hỏa tộc lột xác.","nguon":["@c0355"]},{"id":"bia-khao-nghiem-chu-tuoc","name":"Bia khảo nghiệm Chu Tước","cn":"","category":"phap-bao","categoryLabel":"Pháp khí khảo nghiệm","phamCap":"","soHuu":[],"trangThai":"Đã bị phá hủy","blurb":"Bốn bia dùng để kiểm nghiệm thành quả tu luyện bốn kích của Thái Cổ Chu Tước.","detail":"Bốn bia màu đen được dùng pháp lực luyện hóa từ mảnh vỡ ngôi sao. Sau khi lĩnh ngộ trọn vẹn bốn kích Chu Tước, Thạch Hạo đánh một chưởng khiến cả bốn bia lần lượt nổ tung hoặc sụp đổ.","nguon":["@c0355"]},{"id":"nuoc-vo-tran","name":"Nước Vô Trần","cn":"","category":"khac","categoryLabel":"Bảo dịch","phamCap":"Hiếm có","soHuu":[],"trangThai":"Được dùng trong nghi thức trước khi vào hồ Niết Bàn","blurb":"Bảo dịch dùng để gột sạch bụi trần trước cổ lễ tế tự Chu Tước Thái Cổ.","detail":"Nước Vô Trần không mang thần lực nhưng có thể tẩy sạch bụi trần, hỗ trợ trị thương thể xác và khiến tinh thần trở nên thư thái. Dòng nước này được cho là nước dùng để Thần Linh tắm rửa.","nguon":["@c0356"]},{"id":"huyet-thanh-niet-ban","name":"Huyết thanh niết bàn","cn":"","category":"khac","categoryLabel":"Thần dịch","phamCap":"","soHuu":["Thạch Hạo","Đả Thần Thạch"],"trangThai":"Đã được thu lấy nhiều giọt","blurb":"Thần dịch đỏ tươi pha vàng nhạt sinh ra từ nơi Chu Tước Thái Cổ niết bàn, có khả năng chữa thương và bổ sung tinh hoa.","detail":"Một giọt Huyết thanh niết bàn giúp Thạch Hạo nối lại những đoạn xương gãy và khôi phục sinh khí. Sau khi thu thêm nhiều giọt, Thạch Hạo chữa lành hoàn toàn thương thế do cưỡng ép vận dụng Chí Tôn cốt và trở lại trạng thái đỉnh cao.","nguon":["@c0357"]},{"id":"phu-chu-hung-thu-thuong-co","name":"Phù chú hung thú Thượng Cổ","cn":"","category":"khac","categoryLabel":"Phù chú","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã cháy thành tro","blurb":"Hàng trăm tờ giấy ố vàng có thể hóa thành hung thú cấp Minh Văn cảnh để vây đánh người tiến vào sân thi đấu.","detail":"Những phù chú tồn tại từ thời Thượng Cổ, được bố trí trong sân thi đấu của Bức tường Thần Ma. Mỗi tờ giấy hóa thành một hung thú cấp Minh Văn cảnh; sau khi bị Thạch Hạo đánh chết, chúng trở lại hình dạng giấy ố vàng rồi tự cháy thành tro.","nguon":["@c0358"]},{"id":"la-bua-chu-yem","name":"Lá bùa Chu Yếm","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã cháy thành tro","blurb":"Lá bùa màu vàng có thể tái hiện thần uy cùng các biến hóa của Chu Yếm để thử thách người bước vào sân thi đấu.","detail":"Lá bùa diễn hóa thành một Chu Yếm có năng lực chiến đấu mạnh mẽ, thi triển bảy mươi hai biến và mô phỏng thần thông của đối thủ. Sau khi hóa thân Chu Yếm bị Thạch Hạo giết, nó trở lại nguyên dạng rồi tự bốc cháy thành tro.","nguon":["@c0359"]},{"id":"thuyen-giay-mau-den","name":"Thuyền giấy màu đen","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"Tái xuất trong sân thi đấu sau cửa hình người","blurb":"Chiếc thuyền giấy màu đen cỡ lòng bàn tay từng được Thạch Hạo nhìn thấy tại Bắc Hải.","detail":"Vật phẩm bí ẩn xuất hiện trong sân thi đấu yên tĩnh phía sau cánh cửa đá hình người. Nó lơ lửng rồi từ từ hạ xuống, đánh dấu lần tái xuất sau khi từng được Thạch Hạo bắt gặp tại Bắc Hải.","nguon":["@c0359"]},{"id":"buc-tuong-than-ma","name":"Bức tường Thần Ma","cn":"","category":"khac","categoryLabel":"Cổ vật khảo nghiệm","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang hoạt động trong Thánh Hoàng cung","blurb":"Cổ vật tạo ra các sân đấu và đối thủ thuần huyết để người tham gia giao chiến, tôi luyện.","detail":"Bức tường có nhiều cửa đá dẫn tới các sân đấu, có thể tạo ra sinh linh cổ xưa làm đối thủ và tự điều chỉnh sức mạnh theo cảnh giới của người tham gia. Thạch Hạo dùng nơi này huyết chiến suốt một tháng để mài giũa bảo thuật, phù văn và khả năng chiến đấu.","nguon":["@c0360"]},{"id":"te-dan-ngoi-sao","name":"Tế đàn ngôi sao","cn":"","category":"khac","categoryLabel":"Tế đàn truyền tống","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang hoạt động","blurb":"Tế đàn khắc đầy ngôi sao, dùng để truyền tống người rời khỏi Thánh Hoàng cung.","detail":"Sau khi Hỏa Linh Nhi kết thúc tu hành trong hang Chu Tước, nàng và Thạch Hạo bước lên tế đàn. Ánh sáng lóe lên, đưa cả hai từ trong Thánh Hoàng cung ra bên ngoài.","nguon":["@c0360"]},{"id":"vu-y-bao-vu-do","name":"Vũ y bảo vũ đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Hỏa Linh Nhi"],"trangThai":"Được Tiểu Hồng trao cho Hỏa Linh Nhi","blurb":"Một bộ vũ y dệt từ bảo vũ đỏ đậm, lưu chuyển thần hỏa và phủ dày ký hiệu.","detail":"Tiểu Hồng ban bộ vũ y này cho Hỏa Linh Nhi sau khi xác nhận nàng đã thức tỉnh huyết mạch Chu Tước. Đây là một bảo cụ có giá trị khó tưởng tượng, dùng để bao phủ thân thể Hỏa Linh Nhi.","nguon":["@c0361"]},{"id":"cong-long-mau-do","name":"Cọng lông màu đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được Thạch Hạo giữ","blurb":"Một cọng lông đỏ có khả năng hấp thu lửa Chu Tước.","detail":"Sau khi bị Tiểu Hồng đá bay và bị hỏa diễm bao phủ, Thạch Hạo lấy cọng lông này ra để hấp thu toàn bộ lửa Chu Tước quanh thân, nhờ đó tránh bị ngọn lửa gây thương tổn nghiêm trọng.","nguon":["@c0361"]},{"id":"da-hu-khong-thu","name":"Da Hư Không thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Bà lão đi theo Nguyệt Thiền"],"trangThai":"Bị Hỏa Hoàng phá khả năng che giấu","blurb":"Tấm da có khả năng giúp người sử dụng ẩn mình trong hư không và hỗ trợ dò gợn sóng phù văn.","detail":"Da Hư Không thú từng được bán đấu giá với giá rất cao tại Hoàng Đô Thạch Quốc. Bà lão đi theo Nguyệt Thiền dùng nó để che giấu thân hình khi dò tọa độ truyền tống của Thạch Hạo, nhưng vẫn bị linh thân Hỏa Hoàng phát hiện và đánh trọng thương.","nguon":["@c0364"]},{"id":"truyen-tong-tran-hoa-quoc","name":"Truyền tống trận Hỏa quốc","cn":"","category":"khac","categoryLabel":"Trận đài truyền tống","phamCap":"Chưa rõ","soHuu":["Hỏa quốc"],"trangThai":"Đang hoạt động","blurb":"Trận đài truyền tống đường dài của Hỏa quốc, được dùng để đưa Thạch Hạo tới biên giới phía Tây Thạch Quốc.","detail":"Truyền tống trận nằm tại trọng địa Hỏa tộc, có hình thức một tế đàn lớn được bày đầy phù cốt. Khi vận chuyển, tế đàn phát sáng và mở ra một con đường truyền tống tới khu vực phía Tây Thạch Quốc.","nguon":["@c0364"]},{"id":"tam-chan-nguyen-thuy-bao-cot","name":"Tấm chắn nguyên thủy bảo cốt","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"","soHuu":["Thiếu niên phun sương mù ăn mòn"],"trangThai":"Đã bị phá hủy","blurb":"Tấm chắn phòng ngự luyện từ tàn cốt của một sinh linh thuần huyết chết yểu.","detail":"Tấm chắn có thể phóng lớn để phòng ngự và sở hữu độ cứng rắn cao. Khi được dùng để đỡ chưởng của Thạch Hạo, nó bị sức mạnh thân thể của đối phương đánh nứt rồi phá vỡ.","nguon":["@c0365"]},{"id":"phong-loi-giao","name":"Phong Lôi Giao","cn":"","category":"phap-bao","categoryLabel":"Cung","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Cây cung Thạch Hạo thu được tại tổ địa Hỏa quốc, có thể bắn tên kèm tiếng giao hú.","detail":"Thạch Hạo dùng Phong Lôi Giao đấu cung với Hôi Giao thuần huyết. Những mũi tên từ cây cung tham gia cuộc đối xạ có sức phá núi và khiến một số sinh linh vực ngoại trúng tên rồi nổ tung.","nguon":["@c0365"]},{"id":"huyet-nhuc-hoi-giao-thuan-huyet","name":"Huyết nhục Hôi Giao thuần huyết","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Sinh linh thuần huyết","soHuu":[],"trangThai":"Được chia cho dân làng sử dụng","blurb":"Tài nguyên tu luyện do Thạch Hạo mang về Thạch thôn, có tinh khí mạnh và hiệu quả bồi bổ vượt linh dược thông thường.","detail":"Huyết nhục Hôi Giao thuần huyết được dùng trong bữa tiệc của Thạch thôn, giúp bồi bổ thể chất và hỗ trợ nhiều người đột phá. Đám trẻ ăn quá nhiều phải chạy quanh hồ để tiêu hóa lượng tinh khí mạnh mẽ.","nguon":["@c0367"]},{"id":"mau-giao-long","name":"Máu giao long","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"Đã được dùng để rèn luyện đám trẻ Thạch thôn","blurb":"Tài nguyên tẩy luyện thân thể có sức tẩm bổ mạnh, được sử dụng khi đám trẻ cần luyện hóa tinh khí từ huyết nhục Hôi Giao.","detail":"Các vị tộc trưởng nhỏ vài giọt máu giao long vào đỉnh đồng để rèn luyện đám trẻ sau khi chúng ăn quá nhiều huyết nhục Hôi Giao thuần huyết.","nguon":["@c0367"]},{"id":"thanh-thu-ngan-dao","name":"Thánh thụ ngân đào","cn":"","category":"khac","categoryLabel":"Linh thụ","phamCap":"Chưa nêu","soHuu":[],"trangThai":"Sinh trưởng tại Thạch thôn","blurb":"Linh thụ lưu chuyển thánh huy trắng bạc, cùng Liễu Thần hấp dẫn nhiều linh vật tụ tập tại đầu Thạch thôn.","detail":"Thánh thụ ngân đào tỏa thánh huy trắng bạc. Sự hiện diện của cây cùng Liễu Thần khiến khu vực đầu Thạch thôn thu hút nhiều linh cầm và thụy thú.","nguon":["@c0368"]},{"id":"phap-khi-phu-cot-nguyen-thuy-hu-khong-thu","name":"Pháp khí phù cốt nguyên thủy Hư Không thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí thần linh","soHuu":["Thạch Nghị"],"trangThai":"Đang được sử dụng","blurb":"Pháp khí thần linh luyện từ phù cốt nguyên thủy của Hư Không thú, có khả năng mở thông đạo hư không.","detail":"Pháp khí hiện ra khi hai chiến kích bay khỏi con ngươi của Thạch Nghị rồi hợp thành một thông đạo thần thánh. Nó đưa Thạch Nghị xuyên vào hư không để rời Võ Vương phủ tới hồ Ma Linh.","nguon":["@c0369"]},{"id":"thanh-chi-phong-vo-song-hau","name":"Thánh chỉ phong Vô Song hầu","cn":"","category":"khac","categoryLabel":"Thánh chỉ","phamCap":"","soHuu":["Thạch Nghị"],"trangThai":"Đã hóa thành bột","blurb":"Thánh chỉ của Thạch Hoàng phong Thạch Nghị làm Vô Song hầu, mặt sau có một chữ Nhân.","detail":"Ý chỉ được đưa từ Hoàng thành Thạch Quốc tới Võ Vương phủ ngay trước trận quyết chiến. Sau khi nhìn thấy chữ Nhân ở mặt sau và suy nghĩ về hàm ý của nó, Thạch Nghị dùng ánh mắt khiến toàn bộ thánh chỉ hóa thành bột mịn.","nguon":["@c0369"]},{"id":"phap-khi-qua-lai-thoi-khong","name":"Pháp khí qua lại thời không","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"","soHuu":[],"trangThai":"Đang được sử dụng","blurb":"Pháp khí có khả năng vận chuyển người xuyên qua thời không.","detail":"Pháp khí này mang Thạch Nghị xuyên qua thời không, đưa hắn hạ xuống vùng núi thuộc hồ Ma Linh.","nguon":["@c0370"]},{"id":"chu-vong-thanh-mon","name":"Chu Võng Thánh môn","cn":"","category":"phap-bao","categoryLabel":"Thần võng","phamCap":"","soHuu":["Hồ Ma Linh"],"trangThai":"Cửa vào hồ Ma Linh","blurb":"Tấm mạng nhện thần trắng bạc nằm giữa hai ngọn núi lớn, đóng vai trò cửa vào hồ Ma Linh.","detail":"Chu Võng Thánh môn mang hình dạng một tấm lưới trắng bạc khổng lồ. Tương truyền thần võng có thể bao phủ bầu trời, che khuất trời đất và bắt giữ mọi thứ.","nguon":["@c0370"]},{"id":"dai-lo-mau-vang","name":"Đại lộ màu vàng","cn":"","category":"khac","categoryLabel":"Thông đạo","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang hoạt động","blurb":"Con đường thần bí và thiêng liêng nối tới chiến trường Thiên Không, chỉ dành cho Vực Sứ cùng những người tham gia quyết đấu.","detail":"Vực Sứ dẫn Thạch Hạo và Thạch Nghị theo đại lộ màu vàng lên thiên ngoại. Trên đường có hoa sen và suối ngọt; người quan chiến không được bước lên mà phải tự sử dụng bảo cụ phi hành để đuổi theo.","nguon":["@c0371"]},{"id":"chuong-lon-mau-vang-cua-thach-nghi","name":"Chuông lớn màu vàng của Thạch Nghị","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đạo binh đang thành hình","soHuu":["Thạch Nghị"],"trangThai":"Đang thành hình","blurb":"Đạo binh màu vàng được tái tổ hợp từ những mảnh phù văn của mặt trời vàng, mượn thần lực của Thạch Hạo để thành hình ngay trong trận chiến.","detail":"Chuông phát ra sóng âm có thể khiến thần phách bất ổn và phá nát nhiều rào chắn tại chiến trường Thiên Không. Khi chịu những đòn công kích trực diện của Thạch Hạo, mặt chuông hiện lên các ký hiệu như kinh văn rồi vang ra tiếng tụng niệm chấn động trời đất.","nguon":["@c0375"]},{"id":"chien-giap-trung-dong","name":"Chiến giáp Trùng Đồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Nghị"],"trangThai":"Rạn nứt trong giao chiến","blurb":"Chiến y thần dị do sức sáng tạo của Trùng Đồng ngưng tụ, có khả năng bảo vệ cơ thể và phát ra phù văn hỗ trợ chiến đấu.","detail":"Hào quang từ mắt trái Thạch Nghị ngưng tụ thành những khối tinh thể, trước tiên che phủ các vị trí yếu hại rồi hình thành một bộ chiến giáp bao quanh thân thể. Phù văn do chiến giáp phát ra được dung hợp vào bảo thuật Kim Ô, nhưng lớp giáp sau đó bị sức mạnh Côn Bằng đánh rạn nứt.","nguon":["@c0377"]},{"id":"chien-kich-trung-dong","name":"Chiến kích Trùng Đồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Binh khí phù văn","soHuu":["Thạch Nghị"],"trangThai":"Bị Động Thiên trong cơ thể Thạch Hạo giữ lại","blurb":"Chiến kích do phù văn từ hỗn độn trong Trùng Đồng của Thạch Nghị ngưng tụ, có uy lực suýt chém đôi Thạch Hạo.","detail":"Hỗn độn trong mắt Thạch Nghị hóa thành phù văn rồi ngưng tụ thành chiến kích. Binh khí bổ trúng vai, suýt chém Thạch Hạo thành hai mảnh, nhưng bị một Động Thiên trong cơ thể cậu cố định lại.","nguon":["@c0378"]},{"id":"long-nhen-vang-than-linh-ho-ma-linh","name":"Lông nhện vàng của thần linh hồ Ma Linh","cn":"","category":"khac","categoryLabel":"Bí khí","phamCap":"Tổ tiên bí khí","soHuu":["Kim Chu"],"trangThai":"Bị ký hiệu nơi ngực Thạch Hạo ngăn cản","blurb":"Bí khí do thần linh của tộc Kim Chu lột xác lưu lại, có thể âm thầm xuyên vào chiến trường để ám sát đối thủ.","detail":"Kim Chu phóng những sợi lông nhện vàng cực nhỏ vào chiến trường Thiên Không nhằm ám sát Thạch Hạo. Sát khí này khó phát hiện và không để lại dấu vết, nhưng bị ký hiệu lưu chuyển bên ngoài ngực Thạch Hạo cọ rửa, ngăn lại.","nguon":["@c0380"]},{"id":"cam-khi-thuong-co-bo-thien-giao","name":"Cấm khí thượng cổ của Bổ Thiên giáo","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ cấm kỵ","phamCap":"Thượng cổ","soHuu":["Chung lão"],"trangThai":"Đã được dùng để can thiệp trận quyết chiến","blurb":"Bảo cụ cấm kỵ do Chung lão điều khiển, có thể phát động nguyền rủa vô hình nhằm vào linh hồn.","detail":"Theo lệnh Tích Hoa bà bà, Chung lão vận dụng cấm khí từ bên ngoài để đưa một tia bí lực vào võ đài cấp Thần. Nguyền rủa khiến Thạch Hạo nhất thời mất thần, linh hồn như bị chém tan và suýt ngã xuống chiến trường.","nguon":["@c0380"]},{"id":"tran-hon-thap","name":"Trần Hồn tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đã được dùng để kết liễu Thạch Nghị","blurb":"Tòa tháp được Thạch Hạo cầm trong tay phải khi tung đòn kết liễu Thạch Nghị.","detail":"Thạch Hạo đồng thời vận dụng Trần Hồn tháp, Diệt Hồn châm và bí lực từ Chí Tôn cốt. Đòn hợp kích đánh Thạch Nghị nổ tung và chết ngay tại chỗ.","nguon":["@c0380"]},{"id":"cac-mieng-dong-thau","name":"Các miếng đồng thau","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo đang mang theo","blurb":"Những miếng đồng thau trên người Thạch Hạo bị nhiều cường giả xem như một thần tàng di động đáng tranh đoạt.","detail":"Thạch Hạo cầm ba miếng đồng thau trong lúc vận chuyển thần hi chữa thương. Các Tôn giả cho rằng trên người nó có tổng cộng tám miếng và không muốn chúng rơi vào tay chàng trai bên trong lửa thần.","nguon":["@c0382"]},{"id":"thanh-kiem-than-cua-nguyet-thien","name":"Thanh kiếm thần của Nguyệt Thiền","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Nguyệt Thiền tiên tử"],"trangThai":"Đang được sử dụng","blurb":"Thanh kiếm thần bằng ngọc thạch phủ kín phù văn, được Nguyệt Thiền dùng để đối đầu chàng trai bên trong lửa thần.","detail":"Thân kiếm làm từ ngọc thạch, có phù văn dày đặc và tỏa sáng như bình minh. Nguyệt Thiền từng dùng kiếm phá không gian Thần ma chiến vực để thoát ra ngoài; tại chiến trường Thiên Không, nàng rút kiếm nghênh chiến sáu loại bảo thuật của chàng trai bên trong lửa thần.","nguon":["@c0382"]},{"id":"tam-khien-mau-vang","name":"Tấm khiên màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Kim Chu"],"trangThai":"Đã vỡ vụn","blurb":"Bảo cụ phòng ngự được Kim Chu phun ra để ngăn Thạch Hạo công kích.","detail":"Tấm khiên được dùng trong cuộc giao chiến với Thạch Hạo, nhưng chỉ chống đỡ được vài chiêu trước bốn kích Chu Tước thái cổ rồi vỡ vụn.","nguon":["@c0384"]},{"id":"da-thu-mang-kiem-y-thanh-nhan","name":"Da thú mang kiếm ý thánh nhân","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ cấm kỵ thượng cổ","soHuu":["Thạch Hạo"],"trangThai":"Đã bị Thạch Hạo trấn phong và thu lấy","blurb":"Tấm da thú lưu giữ kiếm ý của thánh nhân thượng cổ, mang sáu chữ cổ màu vàng và ẩn chứa một tiểu thế giới.","detail":"Bảo cụ có thể phát kiếm quang, phóng phù văn giam cầm và kéo mục tiêu vào tiểu thế giới bên trong. Kiếm ý lưu lại có uy lực tương đương một đòn của thánh nhân thượng cổ khi bị áp chế xuống cùng cấp, nhưng sẽ hao tổn khi dùng để công kích. Thạch Hạo mở thập đại Động Thiên, vận chuyển pháp môn Côn Bằng để đánh tan kiếm ý rồi trấn phong da thú. Trong tiểu thế giới của bảo cụ, nó thoáng nhìn thấy hai chữ “Lục Đạo”, cho thấy vật này còn ẩn giấu huyền bí mà chủ cũ chưa từng phát huy.","nguon":["@c0385"]},{"id":"cung-lon-mau-vang","name":"Cung lớn màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Tôn giả cầm cung vàng"],"trangThai":"Bị Thạch Hạo xé tan","blurb":"Bảo cụ được một Tôn giả ẩn trong hư không dùng để liên tục bắn tên vàng tập kích Thạch Hạo.","detail":"Cung có thể bắn tên vàng xuyên phá hư không, nhưng các đòn tập kích cũng giết nhiều tu sĩ đứng gần. Khi áp sát chủ nhân của nó, Thạch Hạo dùng bàn tay như móng vuốt kim bằng xé tan cây cung rồi kéo đứt một cánh tay của đối phương.","nguon":["@c0386"]},{"id":"o-lon-mau-den","name":"Ô lớn màu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ Tôn giả","soHuu":["Tôn giả dùng ô đen"],"trangThai":"Bị hủy do tự giải thể","blurb":"Bảo cụ che phủ bầu trời, trấn áp mục tiêu và buông xuống mưa phù văn sát thương.","detail":"Ô lớn màu đen đối đầu với đòn hợp nhất bốn kích Chu Tước thái cổ của Thạch Hạo rồi tự động giải thể, hóa thành một mặt trời đen nổ tung. Vụ nổ phù văn có sức hủy diệt diện rộng, giết nhiều sinh linh và khiến thương thế của Thạch Hạo nặng thêm.","nguon":["@c0386"]},{"id":"chuong-cong-kich-than-hon","name":"Chuông công kích thần hồn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo cụ","soHuu":["Người của Bổ Thiên giáo âm thầm đánh chuông"],"trangThai":"Chưa rõ","blurb":"Bảo cụ chưa rõ tên thật, dùng tiếng chuông dẫn động sức mạnh nguyền rủa công kích thần hồn Thạch Hạo.","detail":"Tiếng chuông khiến những người xung quanh cảm thấy bình tâm, nhưng đối với Thạch Hạo lại giống như luồng kiếm sắc chém thẳng vào nội tâm. Đòn đánh làm thần hồn nó rung chuyển và dẫn động sức mạnh nguyền rủa công kích linh hồn.","nguon":["@c0386"]}]};
